my $db_name = $ENV{'LEGACY_DB_NAME'} || 'legacy_db';
my $db_host = $ENV{'LEGACY_DB_HOST'} || 'localhost';
my $db_user = $ENV{'LEGACY_DB_USER'} || die "Database user must be set via LEGACY_DB_USER environment variable\n";
my $db_pass = $ENV{'LEGACY_DB_PASS'} || die "Database password must be set via LEGACY_DB_PASS environment variable\n";
my $db_port = $ENV{'LEGACY_DB_PORT'} || 3306;

my $dsn = "DBI:mysql:database=$db_name;host=$db_host;port=$db_port";

sub get_database_connection {
    my $dbh = DBI->connect(
        $dsn,
        $db_user,
        $db_pass,
        {
            RaiseError       => 1,
            AutoCommit       => 1,
            PrintError       => 0,
            mysql_enable_utf8 => 1,
            mysql_auto_reconnect => 1,
            mysql_connect_timeout => 10,
        }
    ) or croak "Failed to connect to database: " . DBI->errstr;

    return $dbh;
}

sub disconnect_database {
    my ($dbh) = @_;
    if ($dbh && $dbh->ping) {
        $dbh->disconnect();
        print "Database connection closed successfully.\n";
    }
    return;
}

sub test_connection {
    my ($dbh) = @_;
    eval {
        my $sth = $dbh->prepare("SELECT 1");
        $sth->execute();
        $sth->finish();
    };
    if ($@) {
        warn "Connection test failed: $@\n";
        return 0;
    }
    return 1;
}

sub execute_query {
    my ($dbh, $sql, @bind_params) = @_;

    my $sth;
    eval {
        $sth = $dbh->prepare($sql);
        $sth->execute(@bind_params);
    };
    if ($@) {
        croak "Query execution failed: $@\nSQL: $sql\n";
    }

    return $sth;
}

sub fetch_all_rows {
    my ($dbh, $sql, @bind_params) = @_;

    my $sth = execute_query($dbh, $sql, @bind_params);
    my $rows = $sth->fetchall_arrayref({});
    $sth->finish();

    return $rows;
}

sub execute_transaction {
    my ($dbh, $code_ref) = @_;

    eval {
        $dbh->begin_work();
        $code_ref->($dbh);
        $dbh->commit();
    };
    if ($@) {
        my $error = $@;
        eval { $dbh->rollback(); };
        if ($@) {
            croak "Transaction rollback also failed: $@\nOriginal error: $error\n";
        }
        croak "Transaction failed and was rolled back: $error\n";
    }

    return 1;
}

